// frontend/src/components/ProtectedRoute.jsx
import { Navigate } from 'react-router-dom';
import { useEffect, useState } from 'react';
import api from '../services/api';

export default function ProtectedRoute({ children, adminOnly = false }) {
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);

  useEffect(() => {
    const checkAuth = async () => {
      const token = localStorage.getItem('token');
      const role = localStorage.getItem('role');
      
      console.log('🔍 ProtectedRoute - Token:', token ? 'exists' : 'none');
      console.log('🔍 ProtectedRoute - Role from localStorage:', role);
      
      if (!token) {
        setIsAuthenticated(false);
        setLoading(false);
        return;
      }

      try {
        const user = await api.getCurrentUser();
        console.log('🔍 ProtectedRoute - User from API:', user);
        console.log('🔍 ProtectedRoute - User role:', user.role);
        
        setIsAuthenticated(true);
        
        // Check if user is admin (check both API response and localStorage)
        const userRole = user.role || role;
        const isUserAdmin = userRole === 'admin';
        setIsAdmin(isUserAdmin);
        
        console.log('🔍 ProtectedRoute - IsAdmin:', isUserAdmin);
        console.log('🔍 ProtectedRoute - adminOnly prop:', adminOnly);
        
        // If adminOnly is true and user is not admin, redirect
        if (adminOnly && !isUserAdmin) {
          console.log('🔍 ProtectedRoute - Redirecting to /dashboard (not admin)');
        }
      } catch (error) {
        console.error('🔍 ProtectedRoute - Auth error:', error);
        localStorage.removeItem('token');
        localStorage.removeItem('role');
        localStorage.removeItem('email');
        setIsAuthenticated(false);
      } finally {
        setLoading(false);
      }
    };

    checkAuth();
  }, [adminOnly]);

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loader"></div>
        <p>Loading...</p>
      </div>
    );
  }

  if (!isAuthenticated) {
    console.log('🔍 ProtectedRoute - Not authenticated, redirecting to /auth');
    return <Navigate to="/auth" replace />;
  }

  // Check admin-only access
  if (adminOnly && !isAdmin) {
    console.log('🔍 ProtectedRoute - Not admin, redirecting to /dashboard');
    return <Navigate to="/dashboard" replace />;
  }

  console.log('🔍 ProtectedRoute - Rendering children');
  return children;
}
